<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'
import { ApiError, apiRequest } from '../auth'
import type { AiConfig, AiStats, KnowledgeSource } from '../knowledge'
import AppShell from '../components/AppShell.vue'

const config = reactive({ enabled: false, public_qa_enabled: false, sales_assistant_enabled: false, welcome_message: '', system_prompt: '', daily_limit: 100 }); const sources = ref<KnowledgeSource[]>([]); const stats = ref<AiStats | null>(null); const message = ref(''); const error = ref(''); const draftResult = ref('')
const source = reactive({ source_type: 'faq', title: '', content: '', is_authorized: true }); const draft = reactive({ draft_type: 'company_intro', product_id: '', context: '' })
async function load() { try { const [current, items, usage] = await Promise.all([apiRequest<AiConfig>('/tenant/ai/config'), apiRequest<KnowledgeSource[]>('/tenant/knowledge/sources'), apiRequest<AiStats>('/tenant/ai/stats')]); Object.assign(config, current); sources.value = items; stats.value = usage } catch (e) { error.value = e instanceof ApiError ? e.message : 'AI 数据加载失败' } }
async function saveConfig() { try { await apiRequest('/tenant/ai/config', { method: 'PUT', body: JSON.stringify(config) }); message.value = 'AI 配置已保存' } catch (e) { error.value = e instanceof ApiError ? e.message : '配置保存失败' } }
async function addSource() { try { await apiRequest('/tenant/knowledge/sources', { method: 'POST', body: JSON.stringify(source) }); Object.assign(source, { title: '', content: '' }); await load() } catch (e) { error.value = e instanceof ApiError ? e.message : '知识索引失败' } }
async function sync() { await apiRequest('/tenant/knowledge/sync', { method: 'POST' }); message.value = '企业和已发布产品已同步'; await load() }
async function sourceAction(item: KnowledgeSource, action: 'disable' | 'retry') { await apiRequest(`/tenant/knowledge/sources/${item.id}/${action}`, { method: 'POST' }); await load() }
async function generate() { try { const result = await apiRequest<{ content: string; notice: string }>('/tenant/ai/drafts', { method: 'POST', body: JSON.stringify({ ...draft, product_id: draft.product_id || null }) }); draftResult.value = `${result.notice}\n${result.content}` } catch (e) { error.value = e instanceof ApiError ? e.message : '草稿生成失败' } }
onMounted(load)
</script>

<template><AppShell><header class="page-header compact"><div><p class="eyebrow">KNOWLEDGE & AI</p><h1>企业知识库与 AI 助手</h1><p>只使用本企业明确授权并已完成索引的内容，所有生成结果均需人工确认。</p></div><button class="secondary-button" @click="sync">同步企业与产品</button></header><div v-if="message" class="notice success">{{ message }}</div><div v-if="error" class="notice error">{{ error }}</div><section class="settings-grid"><form class="panel form-stack" @submit.prevent="saveConfig"><h2>AI 使用配置</h2><label class="checkbox-row"><input v-model="config.enabled" type="checkbox" />启用企业 AI</label><label class="checkbox-row"><input v-model="config.public_qa_enabled" type="checkbox" />允许公开问答</label><label class="checkbox-row"><input v-model="config.sales_assistant_enabled" type="checkbox" />允许销售草稿助手</label><label><span>欢迎语</span><input v-model.trim="config.welcome_message" /></label><label><span>安全提示语</span><textarea v-model.trim="config.system_prompt" rows="3" /></label><label><span>每日公开问答上限</span><input v-model.number="config.daily_limit" type="number" min="1" /></label><button class="primary-button">保存配置</button></form><form class="panel form-stack" @submit.prevent="addSource"><h2>新增授权知识</h2><label><span>类型</span><select v-model="source.source_type"><option value="faq">FAQ</option><option value="case">案例</option><option value="document">文档</option></select></label><label><span>标题</span><input v-model.trim="source.title" required /></label><label><span>解析内容</span><textarea v-model.trim="source.content" rows="8" required /></label><label class="checkbox-row"><input v-model="source.is_authorized" type="checkbox" />确认已获企业授权</label><button class="primary-button">解析并索引</button></form></section><section v-if="stats" class="metric-grid"><article><span>调用量</span><strong>{{ stats.calls }}</strong></article><article><span>失败率</span><strong>{{ (stats.failure_rate * 100).toFixed(1) }}%</strong></article><article><span>无依据回答</span><strong>{{ stats.uncertain }}</strong></article><article><span>反馈</span><strong>{{ stats.positive_feedback }} / {{ stats.negative_feedback }}</strong></article></section><section class="panel table-panel"><h2>知识来源</h2><table><thead><tr><th>来源</th><th>状态</th><th>授权</th><th>索引时间</th><th>操作</th></tr></thead><tbody><tr v-for="item in sources" :key="item.id"><td><b>{{ item.title }}</b><small>{{ item.source_type }} · {{ item.error_message || item.content.slice(0, 60) }}</small></td><td>{{ item.status }}</td><td>{{ item.is_authorized ? '已授权' : '已取消' }}</td><td>{{ item.indexed_at ? new Date(item.indexed_at).toLocaleString() : '—' }}</td><td class="actions"><button v-if="item.status !== 'disabled'" class="link-button danger" @click="sourceAction(item, 'disable')">停用</button><button v-if="item.status === 'failed'" class="link-button" @click="sourceAction(item, 'retry')">重试</button></td></tr></tbody></table></section><form class="panel form-stack" @submit.prevent="generate"><h2>AI 建议草稿</h2><select v-model="draft.draft_type"><option value="company_intro">企业介绍</option><option value="product_copy">产品文案</option><option value="follow_up_suggestion">跟进建议</option></select><input v-if="draft.draft_type === 'product_copy'" v-model.trim="draft.product_id" placeholder="产品 ID" required /><textarea v-model.trim="draft.context" rows="4" placeholder="补充上下文（不会自动修改业务数据）" /><button class="primary-button">生成建议草稿</button><pre v-if="draftResult" class="notice">{{ draftResult }}</pre></form></AppShell></template>
